// ⚙️ CONFIG: set your OpenAI-compatible model here
const MODEL = "policy/EU-Sonnet-4-6";

const item = $input.item;

let content = [
  {
    type: "text",
    text: `
Return ONLY valid JSON.
Do not use markdown.
Do not wrap in triple backticks.
Do not add explanations before or after the JSON.

Use exactly this shape:
{
  "found_invoice": true,
  "reason": "short explanation",
  "relevantAttachmentKeys": ["attachment_0"],
  "invoiceData": {
    "supplierCode": null,
    "supplierName": null,
    "supplierCustomerNumberAtSupplier": null,
    "supplierContactMailAddress": null,
    "supplierIban": null,
    "projectCode": null,
    "projectNumber": null,
    "projectName": null,
    "invoiceNumberSupplier": null,
    "note": null,
    "invoiceDate": null,
    "paymentTermDays": null,
    "discount1Rate": null,
    "discount1Days": null,
    "discount2Rate": null,
    "discount2Days": null,
    "currencyCode": null,
    "invoiceItems": [
      {
        "account": null,
        "costCenter": null,
        "costGroup": null,
        "projectCode": null,
        "taxRate": null,
        "netAmount": null,
        "grossAmount": null,
        "vatAmount": null,
        "note": null
      }
    ]
  }
}

Rules:
- found_invoice = true only if at least one attachment is clearly an incoming supplier invoice / Eingangsrechnung / XRechnung / receipt relevant for accounting.
- relevantAttachmentKeys must contain the original attachment keys like "attachment_0".
- invoiceData field names must match exactly.
- The note field should hold a short description, e.g. the supplier company name combined with the invoice period.
- Each invoiceItems note should be a short note, not more than 50 characters.
- Dates must be ISO-8601 strings if known, otherwise null.
- Do not invent values.
- Aggregate invoiceItems by VAT rate (Mehrwertsteuersatz), not by raw line item.
- Return one invoiceItems entry per VAT bucket.
- Sum netAmount, vatAmount and grossAmount per VAT bucket.
- Only fill account, costCenter, costGroup, projectCode, taxCode if explicitly present in the documents.
- If no invoice is found, return:
  {
    "found_invoice": false,
    "reason": "...",
    "relevantAttachmentKeys": [],
    "invoiceData": {
      "supplierCode": null,
      "supplierName": null,
      "supplierCustomerNumberAtSupplier": null,
      "supplierContactMailAddress": null,
      "supplierIban": null,
      "projectCode": null,
      "projectNumber": null,
      "projectName": null,
      "invoiceNumberSupplier": null,
      "note": null,
      "invoiceDate": null,
      "paymentTermDays": null,
      "discount1Rate": null,
      "discount1Days": null,
      "discount2Rate": null,
      "discount2Days": null,
      "currencyCode": null,
      "invoiceItems": []
    }
  }
`
  }
];

let has_xml_or_json = false;

if (item.binary) {
  for (const key of Object.keys(item.binary)) {
    const file = item.binary[key];

    const mimeType = file.mimeType || "";
    const fileName = file.fileName || "file";

    const buffer = await this.helpers.getBinaryDataBuffer(0, key);
    const base64 = buffer.toString("base64");

    const isPdf =
      mimeType.includes("pdf") ||
      fileName.toLowerCase().endsWith(".pdf");

    if (isPdf) {
      has_xml_or_json = true;
      content.push({
        type: "input_file",
        filename: fileName,
        file_data: `data:application/pdf;base64,${base64}`
      });
    } else if (
      mimeType.includes("xml") ||
      mimeType.includes("json") ||
      fileName.endsWith(".xml") ||
      fileName.endsWith(".json")
    ) {
      has_xml_or_json = true;
      const text = buffer.toString("utf-8");

      content.push({
        type: "text",
        text: `Content of ${fileName}:\n${text}`
      });
    }
  }
}

return {
  json: {
    has_xml_or_json: has_xml_or_json,
    model: MODEL,
    messages: [
      {
        role: "user",
        content
      }
    ]
  }
};

function removeNullish(value) {
  if (Array.isArray(value)) {
    return value.map(removeNullish);
  }

  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value)
        .filter(([, v]) => v !== undefined && v !== null && v !== "")
        .map(([k, v]) => [k, removeNullish(v)])
    );
  }

  return value;
}

let raw = $json.choices[0].message.content ?? "{}";

// remove accidental code fences if the model still adds them
raw = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/, "")
  .trim();

const parsed = JSON.parse(raw);

return {
  json: {
    found_invoice: parsed.found_invoice === true,
    reason: parsed.reason ?? "",
    relevantAttachmentKeys: parsed.relevantAttachmentKeys ?? [],
    invoiceData: removeNullish(parsed.invoiceData ?? {}),
  },
  binary: $input.item.binary
};

const relevantKeys = $json.relevantAttachmentKeys || [];
const sourceBinary = $('When called by parent workflow').item.binary || {};

const keptBinary = Object.fromEntries(
  relevantKeys
    .filter((key) => sourceBinary[key])
    .map((key) => [key, sourceBinary[key]])
);

const invoiceData = { ...($json.invoiceData || {}) };
invoiceData.currency = "EUR";
delete invoiceData.currencyCode;

for (const key of ["invoiceDate", "entryDate", "receiptDate"]) {
  if (
    typeof invoiceData[key] === "string" &&
    /^\d{4}-\d{2}-\d{2}$/.test(invoiceData[key])
  ) {
    invoiceData[key] = `${invoiceData[key]}T00:00:00Z`;
  }
}

const receiptDate = $('When called by parent workflow').item.json.receivedDateTime;

invoiceData.receiptDate = receiptDate;
invoiceData.entryDate = receiptDate;

return {
  json: {
    ...$json,
    invoiceData,
    relevantAttachmentKeys: relevantKeys,
  },
  binary: keptBinary,
};

return {
  json: {
    messageId: $('When called by parent workflow').item.json.id,
    errors: $json.errors,
    invoiceData: $json.data
  }
};

return {
  json: {
    messageId: $('When called by parent workflow').item.json.id,
    success: true
  }
};
